// @name         YMS Quick Notes & UI Improvements - OXY_OS Edition (Optimized)
// @version      3.0
// @description  Technical FUI Overhaul for YMS Dashboard. High Performance Brutalist Technocracy Style.
// @author       @R&S (Optimized)
// @match        https://trans-logistics.amazon.com/yms/shipclerk/*
// @match        https://trans-logistics-eu.amazon.com/yms/shipclerk/*
// @icon         https://api.iconify.design/skill-icons:aws-dark.svg
// @grant        GM_addStyle
// @require      https://code.jquery.com/jquery-3.7.0.min.js
// @run-at       document-end
// ==/UserScript==

(function($, window, document) {
    'use strict';

    // --- CONFIGURATION ---
    const THEME = {
        ACCENT: "#D41B0A",
        BG_DARK: "#0f0f0f",
        SECONDARY: "#2a2a2a",
        DATA_WHITE: "#e0e0e0",
        SUCCESS: "#00FF41",
        INFO: "#0080FF"
    };

    const QUICK_NOTES_CONFIG = {
        page1: {
            "SYSTEM_GENERAL": [
                { text: "RESET", class: "btn-reset", value: "  " },
                { text: "SHIPL", class: "btn-std", value: "SHIP LOAD: " },
                { text: "RENTAL", class: "btn-std", value: "RENTAL VS4 " }
            ],
            "IXD_OPERATIONS": [
                { text: "FWBF1", class: "btn-alert", value: "IXD FWBF1 D&S ISA " },
                { text: "FWBK1", class: "btn-data", value: "IXD FWBK1 D&S ISA " },
                { text: "FWBK2", class: "btn-data", value: "IXD FWBK2 D&S ISA " },
                { text: "FWBK3", class: "btn-data", value: "IXD FWBK3 D&S ISA " },
                { text: "FWBK4", class: "btn-data", value: "IXD FWBK4 D&S ISA " },
                { text: "FWBS1", class: "btn-ok", value: "IXD FWBS1 D&S ISA " },
                { text: "FWBS5", class: "btn-ok", value: "IXD FWBS5 D&S ISA " },
                { text: "FWBS6", class: "btn-ok", value: "IXD FWBS6 D&S ISA " },
                { text: "FWBS7", class: "btn-ok", value: "IXD FWBS7 D&S ISA " },
                { text: "FWBS8", class: "btn-ok", value: "IXD FWBS8 D&S ISA " },
                { text: "FWS10", class: "btn-ok", value: "IXD FWS10 D&S ISA " },
                { text: "FWS12", class: "btn-ok", value: "IXD FWS12 D&S ISA " },
                { text: "FWS13", class: "btn-ok", value: "IXD FWS13 D&S ISA " },
                { text: "FWS14", class: "btn-ok", value: "IXD FWS14 D&S ISA " },
                { text: "FWS15", class: "btn-ok", value: "IXD FWS15 D&S ISA " },
                { text: "FWS16", class: "btn-ok", value: "IXD FWS16 D&S ISA " },
                { text: "AKWPS", class: "btn-alert", value: "IXD AKWPS D&S ISA " },
                { text: "AWZXP", class: "btn-alert", value: "IXD AWZXP D&S ISA " },
                { text: "ATSEU", class: "btn-alert", value: "IXD ATSEU D&S ISA " },
                { text: "FBAPL", class: "btn-alert", value: "IXD FBA PALLETS D&S VRID " },
                { text: "RETAIL", class: "btn-alert", value: "IXD RETAIL PALLETS D&S ISA " },
                { text: "FBALL", class: "btn-alert", value: "IXD FBALL D&S ISA " }
            ],
            "COURIER_LOG": [
                { text: "UPSN", class: "btn-sec", value: "IXD UPSN D&S ISA " },
                { text: "LEG25", class: "btn-sec", value: "IXD LEG25 D&S ISA " },
                { text: "DPDPL", class: "btn-sec", value: "IXD DPDPL D&S ISA " },
                { text: "ICCLL", class: "btn-data", value: "IXD ICWR5 PARCEL D&S ISA " },
                { text: "ICCP", class: "btn-data", value: "IXD ICWR5 PALLETS D&S ISA " },
                { text: "DHLGF", class: "btn-sec", value: "IXD DHLGF D&S ISA " },
                { text: "DEUTP", class: "btn-std", value: "IXD DEUTP ISA " },
                { text: "DHLFX", class: "btn-std", value: "IXD DHLFX ISA " },
                { text: "DAFIX", class: "btn-alert", value: "IXD DAFIX ISA " },
                { text: "GLSFR", class: "btn-ok", value: "IXD GLSFR ISA " }
            ]
        },
        page2: {
            "SYSTEM_GENERAL": [
                { text: "RESET", class: "btn-reset", value: " " },
                { text: "SHIPL", class: "btn-std", value: "SHIP LOAD: " },
                { text: "RENTAL", class: "btn-std", value: "RENTAL VS4 " }
            ],
            "CEQP_STORAGE": [
                { text: "FWBF1", class: "btn-alert", value: "CEQP FWBF1 TRAILER " },
                { text: "F1PALL", class: "btn-alert", value: "CEQP FWBF1 TRAILER NEQP PALLETS " },
                { text: "FWBK1", class: "btn-data", value: "CEQP FWBK1 TRAILER " },
                { text: "FWBK2", class: "btn-data", value: "CEQP FWBK2 TRAILER " },
                { text: "FWBS1", class: "btn-ok", value: "CEQP FWBS1 TRAILER " },
                { text: "STOREIB", class: "btn-sec", value: "EMPTY STORE IB" },
                { text: "STOREOB", class: "btn-sec", value: "EMPTY STORE OB" }
            ]
        }
    };

    // --- CSS INJECTION ---
    function injectStyles() {
        GM_addStyle(`
            :root {
                --accent: ${THEME.ACCENT};
                --bg: ${THEME.BG_DARK};
                --sec: ${THEME.SECONDARY};
                --data: ${THEME.DATA_WHITE};
                --success: ${THEME.SUCCESS};
                --info: ${THEME.INFO};
            }

            /* Sticky Header & Control Panel */
            #custom-options-container {
                display: flex; background: rgba(18, 18, 18, 0.95);
                backdrop-filter: blur(5px);
                border: 1px solid var(--sec); padding: 10px 15px; gap: 25px;
                margin-bottom: 10px; position: sticky; top: 0; z-index: 9999;
                box-shadow: 0 4px 6px rgba(0,0,0,0.3);
                border-top: 2px solid var(--accent);
            }
            .panel h3 {
                color: var(--accent); font-size: 10px; text-transform: uppercase;
                letter-spacing: 2px; margin: 0 0 5px 0; font-family: monospace;
            }

            /* Toggles */
            .oxy-switch {
                display: flex; align-items: center; gap: 8px; cursor: pointer;
            }
            .oxy-switch input { display: none; }
            .oxy-switch .slider {
                width: 32px; height: 14px; background: var(--sec); position: relative; transition: 0.3s;
            }
            .oxy-switch .slider::after {
                content: ''; position: absolute; top: 1px; left: 1px;
                width: 12px; height: 12px; background: var(--data); transition: 0.2s cubic-bezier(0.4, 0.0, 0.2, 1);
            }
            .oxy-switch input:checked + .slider { background: var(--accent); }
            .oxy-switch input:checked + .slider::after { transform: translateX(18px); background: #fff; }

            /* Quick Notes Container */
            #quickNotesContainer {
                background: var(--bg); border-left: 3px solid var(--accent);
                padding: 12px; margin-top: 10px; position: relative;
                box-shadow: 6px 6px 0px rgba(0,0,0,0.4); font-family: 'Courier New', monospace;
            }
            #quickNotesContainer::after {
                content: 'SYSTEM_OXY_v3.0_OPT'; position: absolute; bottom: 2px; right: 5px;
                font-size: 9px; color: var(--sec); letter-spacing: 1px;
            }

            /* Tabs / Paginator */
            .oxy-tabs { display: flex; gap: 5px; margin-bottom: 10px; border-bottom: 1px solid var(--sec); padding-bottom: 5px; }
            .oxy-tab-btn {
                background: transparent; color: var(--sec); border: 1px solid var(--sec);
                padding: 4px 12px; font-size: 10px; cursor: pointer; font-weight: bold;
                transition: 0.2s;
            }
            .oxy-tab-btn.active { background: var(--accent); color: #fff; border-color: var(--accent); }

            /* Brutalist Buttons & Tables */
            .buttonTable { width: 100%; border-collapse: collapse; margin-bottom: 12px; table-layout: fixed; }
            .buttonTable th {
                text-align: left; color: var(--data); font-size: 10px; padding: 4px; border-bottom: 1px solid var(--sec);
                background: repeating-linear-gradient(45deg, transparent, transparent 5px, rgba(255,255,255,0.02) 5px, rgba(255,255,255,0.02) 10px);
            }
            .buttonTable td { padding: 3px; }
            .superuserButton {
                width: 100%; border-radius: 0; border: 1px solid var(--sec); padding: 6px 2px;
                font-family: 'Courier New', monospace; font-size: 10px; font-weight: bold;
                text-transform: uppercase; cursor: pointer; transition: background 0.1s, color 0.1s, transform 0.05s;
                background: transparent; color: var(--data); white-space: nowrap; overflow: hidden; text-overflow: ellipsis;
            }
            .superuserButton:hover { background: var(--data); color: var(--bg); border-color: var(--data); }
            .superuserButton:active { transform: scale(0.97); }

            .btn-alert { border-color: var(--accent); color: var(--accent); }
            .btn-alert:hover { background: var(--accent); color: #fff; border-color: var(--accent); }
            .btn-ok { border-color: var(--success); color: var(--success); }
            .btn-ok:hover { background: var(--success); color: var(--bg); border-color: var(--success); }
            .btn-data { border-color: var(--info); color: var(--info); }
            .btn-data:hover { background: var(--info); color: #fff; border-color: var(--info); }
            .btn-sec { border-color: #777; color: #aaa; }

            /* Copy Trigger Icon */
            .copy-trigger {
                display: inline-flex; justify-content: center; align-items: center;
                width: 14px; height: 14px; border: 1px solid var(--accent); background: var(--accent);
                cursor: pointer; margin-left: 6px; vertical-align: middle; transition: 0.2s; position: relative;
            }
            .copy-trigger::before {
                content: ''; width: 6px; height: 6px; background: var(--bg); transition: 0.2s;
            }
            .copy-trigger:hover::before { background: #fff; transform: scale(0.8); }
            .copy-trigger.copied { background: var(--success); border-color: var(--success); }
            .copy-trigger.copied::before {
                content: '✓'; color: var(--bg); background: transparent; font-size: 10px; line-height: 1; font-weight: bold; transform: none;
            }

            /* Dark Mode Core */
            body.oxy-dark-mode { background: #080808 !important; color: var(--data) !important; }
            body.oxy-dark-mode .table, body.oxy-dark-mode .ship-clerk-dashboard-table {
                background: #111 !important; border: 1px solid var(--sec) !important;
            }
            body.oxy-dark-mode th { background: #1a1a1a !important; color: var(--accent) !important; border-bottom: 2px solid var(--accent) !important; }
            body.oxy-dark-mode tr { border-bottom: 1px solid #222 !important; }
            body.oxy-dark-mode tr:hover td { background: rgba(255,255,255,0.05) !important; }

            /* Fast CSS-based Filtering */
            body.oxy-filter-active .ship-clerk-dashboard-table tbody tr { display: none; }
            body.oxy-filter-active .ship-clerk-dashboard-table tbody tr.oxy-important-row { display: table-row !important; }
        `);
    }

    // --- HTML GENERATORS ---
    // Renderuje HTML z template literals dla lepszej wydajności niż tworzenie nodów jQuery
    function buildNotesHTML(pageData, pageId) {
        let html = `<div id="${pageId}" class="oxy-page-content" style="display: none;">`;
        for (const [category, buttons] of Object.entries(pageData)) {
            html += `<table class="buttonTable"><tr><th colspan="5">${category}</th></tr>`;
            buttons.forEach((btn, index) => {
                if (index % 5 === 0) html += `<tr>`;
                // Używamy data-atrybutów dla event delegation
                html += `<td><button type="button" class="superuserButton ${btn.class}" data-note="${btn.value}" title="${btn.value}">${btn.text}</button></td>`;
                if (index % 5 === 4 || index === buttons.length - 1) html += `</tr>`;
            });
            html += `</table>`;
        }
        html += `</div>`;
        return html;
    }

    // --- LOGIC FUNCTIONS ---
    function setupQuickNotes() {
        if ($("#quickNotesContainer").length || !$("#noteTextArea").is(":visible")) return;

        const html = `
            <div id="quickNotesContainer">
                <div class="oxy-tabs">
                    <button type="button" class="oxy-tab-btn active" data-target="oxyPage1">PAGE 1</button>
                    <button type="button" class="oxy-tab-btn" data-target="oxyPage2">PAGE 2</button>
                </div>
                ${buildNotesHTML(QUICK_NOTES_CONFIG.page1, 'oxyPage1')}
                ${buildNotesHTML(QUICK_NOTES_CONFIG.page2, 'oxyPage2')}
            </div>
        `;

        $("#noteTextArea").after(html);
        $("#oxyPage1").show(); // Pokaż domyślnie pierwszą stronę
    }

    function processDynamicElements() {
        // 1. Dodawanie ikonek kopiowania - selektor :not() zapobiega procesowaniu tych samych elementów
        const unProcessedPlates = $("span[ng-if*='vehicleNumber']:not(.oxy-processed), span[ng-if*='licensePlateIdentifier']:not(.oxy-processed)");

        if (unProcessedPlates.length > 0) {
            unProcessedPlates.each(function() {
                const $el = $(this);
                $el.addClass('oxy-processed'); // Oznacz jako przetworzone dla wydajności

                const textToCopy = $el.text().trim().split("\n")[0];
                if(textToCopy) {
                    const triggerHtml = `<span class="copy-trigger" title="COPY_DATA" data-copy="${textToCopy}"></span>`;
                    $el.after(triggerHtml);
                }
            });
        }

        // 2. Optymalizacja dla filtra: oznaczamy wiersze zawierające ważne tagi, by silnik CSS mógł je łatwo pokazać/ukryć
        if ($("body").hasClass("oxy-filter-active")) {
            tagImportantRows();
        }
    }

    function tagImportantRows() {
        // Znajduje wiersze, które mają określone klasy, a jeszcze nie mają tagu
        $(".ship-clerk-dashboard-table tbody tr:not(.oxy-important-row)").each(function() {
            const $row = $(this);
            const hasStatus = $row.find('.yard-asset-yellow, .yard-asset-red').length > 0;
            const hasMasterLP = $row.find('.masterYardLP td:nth-child(2)').text().trim() !== "";

            if (hasStatus || hasMasterLP) {
                $row.addClass('oxy-important-row');
            }
        });
    }

    function initUI() {
        if ($("#custom-options-container").length) return;

        const uiHtml = `
            <div id="custom-options-container">
                <div class="panel">
                    <h3>SYSTEM_THEME</h3>
                    <label class="oxy-switch">
                        <input id="oxy-dark-toggle" type="checkbox" checked>
                        <span class="slider"></span>
                        <span style="font-size: 10px; color: var(--data); font-family: monospace;">OXY_DARK</span>
                    </label>
                </div>
                <div class="panel">
                    <h3>DATA_FILTER</h3>
                    <label class="oxy-switch">
                        <input id="oxy-filter-toggle" type="checkbox">
                        <span class="slider"></span>
                        <span style="font-size: 10px; color: var(--data); font-family: monospace;">TAGGED_ONLY</span>
                    </label>
                </div>
            </div>
        `;

        $('#mainContainer').before(uiHtml);
        $('body').addClass('oxy-dark-mode'); // Dark mode włączony domyślnie
    }

    // --- INITIALIZATION & EVENT DELEGATION ---
    function main() {
        injectStyles();
        initUI();

        // --- EVENT DELEGATION (High Performance) ---
        // Zamiast bind'ować setki eventów, robimy to raz na elemencie Body/Document

        // 1. Kopiowanie rejestracji
        $(document).on('click', '.copy-trigger', function() {
            const $btn = $(this);
            const text = $btn.data('copy');

            navigator.clipboard.writeText(text).then(() => {
                $btn.addClass('copied');
                setTimeout(() => $btn.removeClass('copied'), 1200);
            });
        });

        // 2. Klikanie Notatek (Quick Notes)
        $(document).on('click', '.superuserButton', function() {
            const noteVal = $(this).data('note');
            const $textarea = $("#noteTextArea");
            if ($textarea.length) {
                $textarea.val(noteVal).get(0).dispatchEvent(new Event("change"));
            }
        });

        // 3. Przełączanie zakładek z notatkami
        $(document).on('click', '.oxy-tab-btn', function() {
            $('.oxy-tab-btn').removeClass('active');
            $(this).addClass('active');

            $('.oxy-page-content').hide();
            $('#' + $(this).data('target')).show();
        });

        // 4. Panel sterowania (Toggles)
        $(document).on('change', '#oxy-dark-toggle', function() {
            $('body').toggleClass('oxy-dark-mode', this.checked);
        });

        $(document).on('change', '#oxy-filter-toggle', function() {
            const isActive = this.checked;
            $('body').toggleClass('oxy-filter-active', isActive);
            if(isActive) tagImportantRows(); // Zaktualizuj tagi, jeśli włączamy
        });

        // --- DEBOUNCED MUTATION OBSERVER ---
        // Eliminuje "lagowanie" aplikacji poprzez grupowanie zmian DOM
        let observerTimeout;
        const observer = new MutationObserver(() => {
            clearTimeout(observerTimeout);
            observerTimeout = setTimeout(() => {
                setupQuickNotes();
                processDynamicElements();
            }, 150); // Skrypt czeka 150ms po ostatniej zmianie w DOM, zanim się uruchomi
        });

        observer.observe(document.body, { childList: true, subtree: true });
    }

    // Odpal skrypt, gdy DOM jest gotowy
    $(document).ready(main);

})(jQuery, window, document);"}
